// Copyright Transpersonal Game Studio. All Rights Reserved.\n// Core_ForceSystem.cpp - Advanced physics force management system\n\n#include \"Core_ForceSystem.h\"\n#include \"Engine/Engine.h\"\n#include \"Engine/World.h\"\n#include \"Components/PrimitiveComponent.h\"\n#include \"PhysicsEngine/PhysicsSettings.h\"\n#include \"Kismet/GameplayStatics.h\"\n\nDEFINE_LOG_CATEGORY(LogForceSystem);\n\n// ============================================================================\n// UCore_ForceSystemComponent Implementation\n// ============================================================================\n\nUCore_ForceSystemComponent::UCore_ForceSystemComponent()\n{\n    PrimaryComponentTick.bCanEverTick = true;\n    PrimaryComponentTick.bStartWithTickEnabled = true;\n    \n    // Initialize force parameters\n    MaxForceRadius = 1000.0f;\n    ForceUpdateFrequency = 60.0f;\n    bEnableGravityModification = true;\n    bEnableWindForces = true;\n    bEnableExplosiveForces = true;\n    \n    // Performance settings\n    MaxSimultaneousForces = 50;\n    ForceOptimizationThreshold = 100.0f;\n    \n    // Initialize force tracking\n    ActiveForces.Reserve(MaxSimultaneousForces);\n    ForceHistory.Reserve(1000);\n}\n\nvoid UCore_ForceSystemComponent::BeginPlay()\n{\n    Super::BeginPlay();\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Force System initialized for %s\"), *GetOwner()->GetName());\n    \n    // Initialize force update timer\n    ForceUpdateTimer = 1.0f / ForceUpdateFrequency;\n    \n    // Register with physics world\n    if (UWorld* World = GetWorld())\n    {\n        World->GetTimerManager().SetTimer(\n            ForceUpdateHandle,\n            this,\n            &UCore_ForceSystemComponent::UpdateForces,\n            ForceUpdateTimer,\n            true\n        );\n    }\n}\n\nvoid UCore_ForceSystemComponent::EndPlay(const EEndPlayReason::Type EndPlayReason)\n{\n    // Clear all active forces\n    ClearAllForces();\n    \n    // Clear timer\n    if (UWorld* World = GetWorld())\n    {\n        World->GetTimerManager().ClearTimer(ForceUpdateHandle);\n    }\n    \n    Super::EndPlay(EndPlayReason);\n}\n\nvoid UCore_ForceSystemComponent::TickComponent(float DeltaTime, ELevelTick TickType, FActorComponentTickFunction* ThisTickFunction)\n{\n    Super::TickComponent(DeltaTime, TickType, ThisTickFunction);\n    \n    // Update force decay and cleanup\n    UpdateForceDecay(DeltaTime);\n    \n    // Performance monitoring\n    if (bEnablePerformanceMonitoring)\n    {\n        MonitorPerformance(DeltaTime);\n    }\n}\n\nvoid UCore_ForceSystemComponent::ApplyRadialForce(const FVector& Origin, float Radius, float Strength, EEng_ForceType ForceType, bool bImpulse)\n{\n    if (!IsValidForceParameters(Radius, Strength))\n    {\n        UE_LOG(LogForceSystem, Warning, TEXT(\"Invalid force parameters: Radius=%.2f, Strength=%.2f\"), Radius, Strength);\n        return;\n    }\n    \n    // Create force data\n    FEng_ForceData ForceData;\n    ForceData.ForceID = GenerateForceID();\n    ForceData.ForceType = ForceType;\n    ForceData.Origin = Origin;\n    ForceData.Direction = FVector::ZeroVector; // Radial force has no single direction\n    ForceData.Magnitude = Strength;\n    ForceData.Radius = Radius;\n    ForceData.Duration = bImpulse ? 0.0f : 1.0f;\n    ForceData.bIsActive = true;\n    ForceData.CreationTime = GetWorld()->GetTimeSeconds();\n    \n    // Apply to all objects in radius\n    TArray<AActor*> AffectedActors;\n    GetActorsInRadius(Origin, Radius, AffectedActors);\n    \n    for (AActor* Actor : AffectedActors)\n    {\n        if (UPrimitiveComponent* PrimComp = Actor->FindComponentByClass<UPrimitiveComponent>())\n        {\n            if (PrimComp->IsSimulatingPhysics())\n            {\n                FVector ForceDirection = (Actor->GetActorLocation() - Origin).GetSafeNormal();\n                FVector FinalForce = ForceDirection * Strength;\n                \n                if (bImpulse)\n                {\n                    PrimComp->AddImpulseAtLocation(FinalForce, Actor->GetActorLocation());\n                }\n                else\n                {\n                    PrimComp->AddForceAtLocation(FinalForce, Actor->GetActorLocation());\n                }\n                \n                // Track affected actor\n                ForceData.AffectedActors.Add(Actor);\n            }\n        }\n    }\n    \n    // Store force data\n    ActiveForces.Add(ForceData);\n    ForceHistory.Add(ForceData);\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Applied radial force: ID=%d, Affected=%d actors\"), ForceData.ForceID, ForceData.AffectedActors.Num());\n}\n\nvoid UCore_ForceSystemComponent::ApplyDirectionalForce(const FVector& Origin, const FVector& Direction, float Strength, float Radius, EEng_ForceType ForceType)\n{\n    if (!IsValidForceParameters(Radius, Strength) || Direction.IsNearlyZero())\n    {\n        UE_LOG(LogForceSystem, Warning, TEXT(\"Invalid directional force parameters\"));\n        return;\n    }\n    \n    // Create force data\n    FEng_ForceData ForceData;\n    ForceData.ForceID = GenerateForceID();\n    ForceData.ForceType = ForceType;\n    ForceData.Origin = Origin;\n    ForceData.Direction = Direction.GetSafeNormal();\n    ForceData.Magnitude = Strength;\n    ForceData.Radius = Radius;\n    ForceData.Duration = 1.0f;\n    ForceData.bIsActive = true;\n    ForceData.CreationTime = GetWorld()->GetTimeSeconds();\n    \n    // Apply to all objects in radius\n    TArray<AActor*> AffectedActors;\n    GetActorsInRadius(Origin, Radius, AffectedActors);\n    \n    for (AActor* Actor : AffectedActors)\n    {\n        if (UPrimitiveComponent* PrimComp = Actor->FindComponentByClass<UPrimitiveComponent>())\n        {\n            if (PrimComp->IsSimulatingPhysics())\n            {\n                FVector FinalForce = Direction * Strength;\n                PrimComp->AddForceAtLocation(FinalForce, Actor->GetActorLocation());\n                \n                ForceData.AffectedActors.Add(Actor);\n            }\n        }\n    }\n    \n    ActiveForces.Add(ForceData);\n    ForceHistory.Add(ForceData);\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Applied directional force: ID=%d, Direction=%s\"), ForceData.ForceID, *Direction.ToString());\n}\n\nvoid UCore_ForceSystemComponent::ApplyGravityModification(const FVector& Origin, float Radius, float GravityMultiplier, float Duration)\n{\n    if (!bEnableGravityModification)\n    {\n        UE_LOG(LogForceSystem, Warning, TEXT(\"Gravity modification is disabled\"));\n        return;\n    }\n    \n    // Create gravity modification force\n    FEng_ForceData ForceData;\n    ForceData.ForceID = GenerateForceID();\n    ForceData.ForceType = EEng_ForceType::GravityModification;\n    ForceData.Origin = Origin;\n    ForceData.Direction = FVector(0, 0, -1); // Down\n    ForceData.Magnitude = GravityMultiplier;\n    ForceData.Radius = Radius;\n    ForceData.Duration = Duration;\n    ForceData.bIsActive = true;\n    ForceData.CreationTime = GetWorld()->GetTimeSeconds();\n    \n    // Apply gravity modification to objects in radius\n    TArray<AActor*> AffectedActors;\n    GetActorsInRadius(Origin, Radius, AffectedActors);\n    \n    for (AActor* Actor : AffectedActors)\n    {\n        if (UPrimitiveComponent* PrimComp = Actor->FindComponentByClass<UPrimitiveComponent>())\n        {\n            if (PrimComp->IsSimulatingPhysics())\n            {\n                // Modify gravity scale\n                PrimComp->SetEnableGravity(GravityMultiplier > 0.0f);\n                \n                // Store original gravity for restoration\n                if (!OriginalGravityScales.Contains(Actor))\n                {\n                    OriginalGravityScales.Add(Actor, PrimComp->GetMass());\n                }\n                \n                ForceData.AffectedActors.Add(Actor);\n            }\n        }\n    }\n    \n    ActiveForces.Add(ForceData);\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Applied gravity modification: Multiplier=%.2f, Duration=%.2f\"), GravityMultiplier, Duration);\n}\n\nvoid UCore_ForceSystemComponent::ClearAllForces()\n{\n    // Restore original gravity scales\n    for (auto& GravityPair : OriginalGravityScales)\n    {\n        if (IsValid(GravityPair.Key))\n        {\n            if (UPrimitiveComponent* PrimComp = GravityPair.Key->FindComponentByClass<UPrimitiveComponent>())\n            {\n                PrimComp->SetEnableGravity(true);\n            }\n        }\n    }\n    OriginalGravityScales.Empty();\n    \n    // Clear active forces\n    ActiveForces.Empty();\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"All forces cleared\"));\n}\n\nvoid UCore_ForceSystemComponent::RemoveForce(int32 ForceID)\n{\n    for (int32 i = ActiveForces.Num() - 1; i >= 0; --i)\n    {\n        if (ActiveForces[i].ForceID == ForceID)\n        {\n            ActiveForces[i].bIsActive = false;\n            ActiveForces.RemoveAt(i);\n            UE_LOG(LogForceSystem, Log, TEXT(\"Removed force ID: %d\"), ForceID);\n            break;\n        }\n    }\n}\n\nTArray<FEng_ForceData> UCore_ForceSystemComponent::GetActiveForces() const\n{\n    return ActiveForces;\n}\n\nTArray<FEng_ForceData> UCore_ForceSystemComponent::GetForceHistory() const\n{\n    return ForceHistory;\n}\n\nbool UCore_ForceSystemComponent::IsValidForceParameters(float Radius, float Strength) const\n{\n    return Radius > 0.0f && Radius <= MaxForceRadius && FMath::Abs(Strength) > SMALL_NUMBER;\n}\n\nint32 UCore_ForceSystemComponent::GenerateForceID()\n{\n    static int32 NextForceID = 1;\n    return NextForceID++;\n}\n\nvoid UCore_ForceSystemComponent::GetActorsInRadius(const FVector& Origin, float Radius, TArray<AActor*>& OutActors)\n{\n    if (UWorld* World = GetWorld())\n    {\n        // Use sphere overlap to find actors\n        TArray<FOverlapResult> OverlapResults;\n        FCollisionQueryParams QueryParams;\n        QueryParams.bTraceComplex = false;\n        QueryParams.AddIgnoredActor(GetOwner());\n        \n        bool bHit = World->OverlapMultiByChannel(\n            OverlapResults,\n            Origin,\n            FQuat::Identity,\n            ECollisionChannel::ECC_WorldDynamic,\n            FCollisionShape::MakeSphere(Radius),\n            QueryParams\n        );\n        \n        if (bHit)\n        {\n            for (const FOverlapResult& Result : OverlapResults)\n            {\n                if (Result.GetActor())\n                {\n                    OutActors.AddUnique(Result.GetActor());\n                }\n            }\n        }\n    }\n}\n\nvoid UCore_ForceSystemComponent::UpdateForces()\n{\n    float CurrentTime = GetWorld()->GetTimeSeconds();\n    \n    // Update active forces and remove expired ones\n    for (int32 i = ActiveForces.Num() - 1; i >= 0; --i)\n    {\n        FEng_ForceData& Force = ActiveForces[i];\n        \n        // Check if force has expired\n        if (Force.Duration > 0.0f && (CurrentTime - Force.CreationTime) >= Force.Duration)\n        {\n            Force.bIsActive = false;\n            ActiveForces.RemoveAt(i);\n            continue;\n        }\n        \n        // Apply continuous forces\n        if (Force.ForceType != EEng_ForceType::Impulse)\n        {\n            ApplyContinuousForce(Force);\n        }\n    }\n}\n\nvoid UCore_ForceSystemComponent::UpdateForceDecay(float DeltaTime)\n{\n    // Update force decay for active forces\n    for (FEng_ForceData& Force : ActiveForces)\n    {\n        if (Force.bHasDecay)\n        {\n            Force.Magnitude *= FMath::Max(0.0f, 1.0f - (Force.DecayRate * DeltaTime));\n            \n            // Remove force if magnitude becomes negligible\n            if (Force.Magnitude < ForceOptimizationThreshold)\n            {\n                Force.bIsActive = false;\n            }\n        }\n    }\n}\n\nvoid UCore_ForceSystemComponent::ApplyContinuousForce(const FEng_ForceData& ForceData)\n{\n    // Apply force to all affected actors\n    for (AActor* Actor : ForceData.AffectedActors)\n    {\n        if (IsValid(Actor))\n        {\n            if (UPrimitiveComponent* PrimComp = Actor->FindComponentByClass<UPrimitiveComponent>())\n            {\n                if (PrimComp->IsSimulatingPhysics())\n                {\n                    FVector ForceToApply;\n                    \n                    switch (ForceData.ForceType)\n                    {\n                    case EEng_ForceType::Radial:\n                        ForceToApply = (Actor->GetActorLocation() - ForceData.Origin).GetSafeNormal() * ForceData.Magnitude;\n                        break;\n                    case EEng_ForceType::Directional:\n                        ForceToApply = ForceData.Direction * ForceData.Magnitude;\n                        break;\n                    case EEng_ForceType::Wind:\n                        ForceToApply = ForceData.Direction * ForceData.Magnitude * GetWindMultiplier(Actor->GetActorLocation());\n                        break;\n                    default:\n                        ForceToApply = ForceData.Direction * ForceData.Magnitude;\n                        break;\n                    }\n                    \n                    PrimComp->AddForceAtLocation(ForceToApply, Actor->GetActorLocation());\n                }\n            }\n        }\n    }\n}\n\nfloat UCore_ForceSystemComponent::GetWindMultiplier(const FVector& Location) const\n{\n    // Simple wind variation based on height and distance from origin\n    float HeightFactor = FMath::Max(0.1f, Location.Z / 1000.0f);\n    float NoiseFactor = FMath::PerlinNoise1D(Location.X * 0.001f + GetWorld()->GetTimeSeconds() * 0.1f);\n    \n    return HeightFactor * (1.0f + NoiseFactor * 0.5f);\n}\n\nvoid UCore_ForceSystemComponent::MonitorPerformance(float DeltaTime)\n{\n    // Track performance metrics\n    static float PerformanceTimer = 0.0f;\n    PerformanceTimer += DeltaTime;\n    \n    if (PerformanceTimer >= 1.0f) // Update every second\n    {\n        int32 ActiveForceCount = ActiveForces.Num();\n        float MemoryUsage = ActiveForceCount * sizeof(FEng_ForceData);\n        \n        if (ActiveForceCount > MaxSimultaneousForces * 0.8f)\n        {\n            UE_LOG(LogForceSystem, Warning, TEXT(\"High force count: %d/%d\"), ActiveForceCount, MaxSimultaneousForces);\n        }\n        \n        PerformanceTimer = 0.0f;\n    }\n}\n\n// ============================================================================\n// UCore_ForceSystemSubsystem Implementation\n// ============================================================================\n\nvoid UCore_ForceSystemSubsystem::Initialize(FSubsystemCollectionBase& Collection)\n{\n    Super::Initialize(Collection);\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Force System Subsystem initialized\"));\n    \n    // Initialize global force settings\n    GlobalForceMultiplier = 1.0f;\n    bGlobalForceSystemEnabled = true;\n    MaxGlobalForces = 200;\n    \n    // Clear global force tracking\n    GlobalActiveForces.Empty();\n    GlobalActiveForces.Reserve(MaxGlobalForces);\n}\n\nvoid UCore_ForceSystemSubsystem::Deinitialize()\n{\n    // Clear all global forces\n    GlobalActiveForces.Empty();\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Force System Subsystem deinitialized\"));\n    \n    Super::Deinitialize();\n}\n\nvoid UCore_ForceSystemSubsystem::ApplyGlobalRadialForce(const FVector& Origin, float Radius, float Strength, EEng_ForceType ForceType)\n{\n    if (!bGlobalForceSystemEnabled)\n    {\n        return;\n    }\n    \n    // Apply force using all registered force components\n    for (TWeakObjectPtr<UCore_ForceSystemComponent> WeakComponent : RegisteredComponents)\n    {\n        if (UCore_ForceSystemComponent* Component = WeakComponent.Get())\n        {\n            Component->ApplyRadialForce(Origin, Radius, Strength * GlobalForceMultiplier, ForceType, false);\n        }\n    }\n    \n    UE_LOG(LogForceSystem, Log, TEXT(\"Applied global radial force: Origin=%s, Radius=%.2f\"), *Origin.ToString(), Radius);\n}\n\nvoid UCore_ForceSystemSubsystem::RegisterForceComponent(UCore_ForceSystemComponent* Component)\n{\n    if (Component)\n    {\n        RegisteredComponents.AddUnique(Component);\n        UE_LOG(LogForceSystem, Log, TEXT(\"Registered force component: %s\"), *Component->GetOwner()->GetName());\n    }\n}\n\nvoid UCore_ForceSystemSubsystem::UnregisterForceComponent(UCore_ForceSystemComponent* Component)\n{\n    if (Component)\n    {\n        RegisteredComponents.Remove(Component);\n        UE_LOG(LogForceSystem, Log, TEXT(\"Unregistered force component: %s\"), *Component->GetOwner()->GetName());\n    }\n}\n\nint32 UCore_ForceSystemSubsystem::GetTotalActiveForces() const\n{\n    int32 TotalForces = 0;\n    for (TWeakObjectPtr<UCore_ForceSystemComponent> WeakComponent : RegisteredComponents)\n    {\n        if (UCore_ForceSystemComponent* Component = WeakComponent.Get())\n        {\n            TotalForces += Component->GetActiveForces().Num();\n        }\n    }\n    return TotalForces;\n}\n\nvoid UCore_ForceSystemSubsystem::SetGlobalForceMultiplier(float Multiplier)\n{\n    GlobalForceMultiplier = FMath::Max(0.0f, Multiplier);\n    UE_LOG(LogForceSystem, Log, TEXT(\"Global force multiplier set to: %.2f\"), GlobalForceMultiplier);\n}\n\nvoid UCore_ForceSystemSubsystem::EnableGlobalForceSystem(bool bEnable)\n{\n    bGlobalForceSystemEnabled = bEnable;\n    UE_LOG(LogForceSystem, Log, TEXT(\"Global force system %s\"), bEnable ? TEXT(\"enabled\") : TEXT(\"disabled\"));\n}"